var config = {
    // <language code>-<country/region code>
    name: "fr-FR",
      // The "numberFormat" defines general number formatting rules.
    numberFormat: {
        //numberFormat has only negative pattern unlike the percent and currency
        //negative pattern: one of (n)|-n|- n|n-|n -
        pattern: ["-n"],
        //number of decimal places
        decimals: 2,
        //string that separates the number groups (1,000,000)
        ",": " ",
        // A string that separates a number from the fractional point.
        ".": ",",
        //the length of each number group
        groupSize: [3],
        //formatting rules for percent number
        percent: {
            //[negative pattern, positive pattern]
            // negativePattern: one of -n %|-n%|-%n|%-n|%n-|n-%|n%-|-% n|n %-|% n-|% -n|n- %
            //positivePattern: one of n %|n%|%n|% n
            pattern: ["-n %", "n %"],
            // The number of decimal places.
            decimals: 2,
            // The string that separates the number groups (1,000,000 %).
            ",": " ",
            // The string that separates a number from the fractional point.
            ".": ",",
            // The length of each number group.
            groupSize: [3],
            //percent symbol
            symbol: "%"
        },
        currency: {
            // [negative pattern, positive pattern]
            // negativePattern: one of "($n)|-$n|$-n|$n-|(n$)|-n$|n-$|n$-|-n $|-$ n|n $-|$ n-|$ -n|n- $|($ n)|(n $)"
            //positivePattern: one of "$n|n$|$ n|n $"
            pattern: ["-$n", "$n"],
            // The number of decimal places.
            decimals: 2,
            // The string that separates the number groups (1,000,000 $).
            ",": " ",
            // The string that separates a number from the fractional point.
            ".": ",",
            // The length of each number group.
            groupSize: [3],
            // The currency symbol.
            symbol: ""
        }
    },
    calendars: {
        standard: {
            days: {
                // The full day names.
                names: ["[resource_displayname[Sunday]]", "[resource_displayname[Monday]]", "[resource_displayname[Tuesday]]", "[resource_displayname[Wednesday]]", "[resource_displayname[Thursday]]", "[resource_displayname[Friday]]", "resource_displayname[Saturday]]"],
                // The abbreviated day names.
                 namesAbbr: ["[resource_shortdisplayname[Sunday]]", "[resource_shortdisplayname[Monday]]", "[resource_shortdisplayname[Tuesday]]", "[resource_shortdisplayname[Wednesday]]", "[resource_shortdisplayname[Thursday]]", "[resource_shortdisplayname[Friday]]", "resource_shortdisplayname[Saturday]]"],
                // The shortest day names.
                namesShort: ["[resource_shortdisplayname[Sunday]]", "[resource_shortdisplayname[Monday]]", "[resource_shortdisplayname[Tuesday]]", "[resource_shortdisplayname[Wednesday]]", "[resource_shortdisplayname[Thursday]]", "[resource_shortdisplayname[Friday]]", "resource_shortdisplayname[Saturday]]"],
            },
            months: {
                // The full month names.
                names: ["[resource_displayname[January]]", "[resource_displayname[February]]", "[resource_displayname[March]]", "[resource_displayname[April]]", "[resource_displayname[May]]", "[resource_displayname[June]]", "[resource_displayname[July]]", "[resource_displayname[August]]", "[resource_displayname[September]]", "[resource_displayname[October]]", "[resource_displayname[November]]", "[resource_displayname[December]]"],
                // abbreviated month names
                namesAbbr: ["[resource_shortdisplayname[January]]", "[resource_shortdisplayname[February]]", "[resource_shortdisplayname[March]]", "[resource_shortdisplayname[April]]", "[resource_shortdisplayname[May]]", "[resource_shortdisplayname[June]]", "[resource_shortdisplayname[July]]", "[resource_shortdisplayname[August]]", "[resource_shortdisplayname[September]]", "[resource_shortdisplayname[October]]", "[resource_shortdisplayname[November]]", "[resource_shortdisplayname[December]]"],
            },
              // The AM and PM designators.
              // [standard,lowercase,uppercase]
            AM: [ "AM", "am", "AM" ],
            PM: [ "PM", "pm", "PM" ],
              // The set of predefined date and time patterns used by the culture.
            patterns: {
                standard: "[resource_displayname[dateformat]]",
                d: "[resource_displayname[dateformat]]",
                D: "dddd, MMMM dd, yyyy",
                F: "dddd, MMMM dd, yyyy h:mm:ss tt",
                g: "[resource_displayname[dateformat]] h:mm tt",
                G: "[resource_displayname[dateformat]] h:mm:ss tt",
                m: "MMMM dd",
                M: "MMMM dd",
                s: "yyyy'-'MM'-'ddTHH':'mm':'ss",
                t: "h:mm tt",
                T: "h:mm:ss tt",
                u: "yyyy'-'MM'-'dd HH':'mm':'ss'Z'",
                y: "MMMM, yyyy",
                Y: "MMMM, yyyy"
            },
              // The first day of the week (0 = Sunday, 1 = Monday, and so on).
            firstDay: 0
        }
    }
};
kendo.cultures["fr-FR"] = config;
kendo.culture(session.culture);

exportPackages: async function(vars) {
    var exportedData = (await api.get("Core/App(" + vars.SourceApp.Id + ")/Export()?$expand=Items")).value;
    if(vars.ForceUpdate == true) {
        for(var package of exportedData) {
            for(var item of package.Items) {
                var data = JSON.parse(item.Data);
                for(var record of data) {
                    if(record.hasOwnProperty('LastUpdated')) {
                        record.LastUpdated = (new Date()).toISOString();
                    } else if(record.hasOwnProperty('CreatedOn')) {
                        record.CreatedOn = (new Date()).toISOString();
                    }
                }
                item.Data = JSON.stringify(data);
            }
        }
    }
    
    vars.ExportedPackages = exportedData;
},
getSelectedPackages: async function (vars) {
    vars.Packages = vars.ExportedPackages.filter(r => vars.SelectedPackageNames.filter(x => x == r.Name).length > 0);
},
getAppCultures: async function (vars) {
    vars.AppCultures = (await api.get("Core/App(" + vars.SourceApp.Id + ")?$expand=Cultures")).Cultures.map(c => ({ CultureId: c.CultureId }));
},
createExternalApi: async function (vars) {
    var apiSendBackup = api.send;
    api.send = function (type, query, data) {
        var d = new Date();
        var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
        var message = type + "-" + query;
        if (data !== null && !query.includes("ImportThis")) {
            var json = JSON.stringify(data, null, 2);
            message = message + "<br>" + json; // spacing level = 2
        }
        console.debug(message);
        return apiSendBackup.apply(api, [type, query, data]);
    };

},
loginExternalApi: async function(vars) {
    console.log("Logging into API instance: " + vars.RemoteAuth.Api);
    vars.ExternalApi = new Api({
        apiRoot: vars.RemoteAuth.Api
    });

    await vars.ExternalApi.login(vars.RemoteAuth.User, vars.RemoteAuth.Pass, true);
},
updateApp: async function(vars) {
    vars.AppExists = (await vars.ExternalApi.get("Core/App?$filter=Domain eq '" + vars.Domain + "'")).value;
    vars.App = vars.AppExists[0];
    console.log("Updating default theme, default culture id & linked cultures on target app");
    vars.App.DefaultCultureId = vars.SourceApp.DefaultCultureId;
    vars.App.DefaultTheme = vars.SourceApp.DefaultTheme;
    if (vars.SelectedPackageNames.filter(r => r == "AppCultures").length > 0) {
        vars.App.Cultures = vars.AppCultures;
    }
    await vars.ExternalApi.update("Core/App(" + vars.App.Id + ")?$expand=Cultures", vars.App);
},
importPackages: async function (vars) {
    for (var i = 0; i < vars.Packages.length; i = i + 1) {
        console.log("Importing " + vars.Packages[i].Name);
        await vars.ExternalApi.add("Core/Package/ImportThis?appId=" + vars.App.Id, [vars.Packages[i]]);
    }
},
getFiles: async function (vars) {
    vars.Files = [];
    if (vars.SelectedPackageNames.filter(r => r == "DMS").length > 0) {
        var query = "";
        for (var i = 0; i < vars.DMSPaths.length; i = i + 1) {
            query += "'" + vars.DMSPaths[i] + "',";
        }
        query = query.substring(0, query.length - 1);
        var folderContents = (await api.get("Core/Folder?$select=Id&$filter=AppId eq " + vars.SourceApp.Id + " and Path in (" + query + ")")).value;
        for (var i = 0; i < folderContents.length; i = i + 1) {
            var folderFiles = (await api.get("Core/File?$filter=FolderId eq " + folderContents[i].Id)).value;
            for (var j = 0; j < folderFiles.length; j = j + 1) {
                vars.Files.push(folderFiles[j]);
            }
        }
    }
},
uploadDMS: async function(vars) {
    for (var i = 0; i < vars.Files.length; i = i + 1) {
        var blob = await new Promise(function (resolve, reject) {
            console.log("Retrieving " + vars.Files[i].Path);
            var sourceReq = new XMLHttpRequest();
            sourceReq.open("GET", "/Api/DMS/" + vars.Files[i].Path + "?t=" + session.token, true);
            sourceReq.setRequestHeader("Authorization", "bearer " + session.token);
            sourceReq.responseType = "blob";
            sourceReq.onload = function (oEvent) {
                if (this.readyState === 4 && this.status >= 200 & this.status <= 300) {
                    resolve(this.response);
                } else {
                    reject(this.status);
                }
            };
            sourceReq.send();
        });
        await new Promise(function (resolve, reject) {
            console.log("Sending " + vars.Files[i].Path);
            var destReq = new XMLHttpRequest();
            destReq.open("PUT", vars.ExternalApi.apiRoot + "DMS/" + vars.Files[i].Path, true);
            destReq.setRequestHeader("Authorization", "bearer " + vars.ExternalApi.token);
            destReq.setRequestHeader("Content-Type", vars.Files[i].MimeType);
            destReq.onload = function (oEvent) {
                if (this.readyState === 4 && this.status >= 200 && this.status <= 300) {
                    resolve(this.response);
                } else {
                    reject(this.status);
                }
            };
            destReq.send(blob);
        });
    }
},
finish: async function(vars) {
}
